-- Singularity Neo capability-scoped shared workflow seed
-- Seeds the shared Enterprise and Brokerage SDLC flows into existing capabilities.
-- Note:
--   The Enterprise workflow uses the default SDLC phase set.
--   The Brokerage workflow uses Inception, Elaboration, Construction, and Delivery.
--   Capabilities with other custom lifecycles may still need the workflow regenerated or adjusted after import.

BEGIN;

DO $$
BEGIN
  IF NOT EXISTS (
    SELECT 1
    FROM information_schema.tables
    WHERE table_schema = 'public'
      AND table_name = 'capability_workflows'
  ) THEN
    RAISE EXCEPTION 'Table "capability_workflows" does not exist. Load the schema first.';
  END IF;
END $$;

CREATE TEMP TABLE tmp_singularity_seed_capabilities ON COMMIT DROP AS
SELECT
  cap.id AS capability_id,
  LEFT(
    TRIM(
      BOTH '-'
      FROM REGEXP_REPLACE(UPPER(cap.id), '[^A-Z0-9]+', '-', 'g')
    ),
    24
  ) AS capability_slug,
  COALESCE(
    NULLIF(cap.special_agent_id, ''),
    'AGENT-' ||
      LEFT(
        TRIM(
          BOTH '-'
          FROM REGEXP_REPLACE(
            UPPER(COALESCE(NULLIF(cap.name, ''), cap.id, 'CAPABILITY')),
            '[^A-Z0-9]+',
            '-',
            'g'
          )
        ),
        24
      ) ||
      '-OWNER'
  ) AS owner_agent_id
FROM capabilities cap;

WITH workflow_templates AS (
  SELECT
    'STANDARD-SDLC'::TEXT AS workflow_suffix,
    'Enterprise SDLC Flow'::TEXT AS workflow_name,
    'Standard SDLC workflow with explicit agent hand-offs, standard input/output document artifacts, governance validation, and human approval before release.'::TEXT AS workflow_summary,
    '{"nodes":[{"id":"NODE-CAPABILITYIDTOKEN-START","name":"Start","type":"START","phase":"ANALYSIS","layout":{"x":80,"y":48},"description":"Entry point for the Enterprise SDLC Flow."},{"id":"STEP-CAPABILITYIDTOKEN-1","name":"Planning & Stakeholder Synthesis","type":"DELIVERY","phase":"ANALYSIS","layout":{"x":340,"y":48},"agentId":"AGENT-CAPABILITYIDTOKEN-PLANNING","action":"Collect stakeholder and capability inputs, align participating agents, and publish the planning report.","description":"Synthesize stakeholder expectations, capability context, and delivery constraints into a planning report that the rest of the SDLC flow can execute against.","inputArtifactId":"Capability Charter","outputArtifactId":"Planning Report","exitCriteria":["Stakeholder inputs consolidated","Planning report published","Milestone assumptions ready for business analysis"],"templatePath":"/out/steps/planning-step-template.md","allowedToolIds":["workspace_list","workspace_read","workspace_search"],"executionNotes":"Planning should gather capability metadata, stakeholder inputs, and upstream agent context without modifying source code.","artifactContract":{"requiredInputs":["Capability Charter","Stakeholder Requirements","Capability Operating Model","Cross-Agent Input Briefs"],"expectedOutputs":["Planning Report","Delivery Milestone Plan","Stakeholder Alignment Summary","Planning Assumptions Log"],"notes":"Planning should produce a durable synthesis of stakeholder intent, milestones, and cross-agent expectations before detailed analysis begins."}},{"id":"STEP-CAPABILITYIDTOKEN-2","name":"Business Analysis","type":"DELIVERY","phase":"ANALYSIS","layout":{"x":600,"y":48},"agentId":"AGENT-CAPABILITYIDTOKEN-BUSINESS-ANALYST","action":"Refine the story, scope, and acceptance criteria.","description":"Clarify the business outcome, define acceptance criteria, and prepare the story for architecture review.","inputArtifactId":"Capability Charter","outputArtifactId":"Requirements Specification","exitC