n implementation-ready technical contract."}},{"id":"STEP-CAPABILITYIDTOKEN-4","name":"Implementation","type":"DELIVERY","phase":"DEVELOPMENT","layout":{"x":1120,"y":400},"agentId":"AGENT-CAPABILITYIDTOKEN-SOFTWARE-DEVELOPER","action":"Implement the change and prepare it for validation.","description":"Build the feature, update tests, and produce implementation notes for downstream QA.","inputArtifactId":"Solution Design Document","outputArtifactId":"Code Change Set","exitCriteria":["Code changes completed","Developer checks passed","Build candidate ready for QA"],"templatePath":"/out/steps/development-step-template.md","allowedToolIds":["workspace_list","workspace_read","workspace_search","git_status","workspace_write","run_build","run_test"],"executionNotes":"Implementation can modify files inside the current desktop-user workspace mapping and should run build/test validation before completing the step.","artifactContract":{"requiredInputs":["Solution Design Document","Architecture Decision Log","Developer Handoff Packet","Acceptance Criteria Matrix"],"expectedOutputs":["Code Change Set","Developer Test Evidence","Implementation Notes","Build Candidate Manifest"],"notes":"Development should produce both executable change evidence and a clear trace of what was implemented."}},{"id":"STEP-CAPABILITYIDTOKEN-5","name":"Quality Assurance","type":"DELIVERY","phase":"QA","layout":{"x":1380,"y":576},"agentId":"AGENT-CAPABILITYIDTOKEN-QA","action":"Validate the build candidate and collect test evidence.","description":"Run quality validation, regression checks, and document release readiness for governance review.","inputArtifactId":"Build Candidate Manifest","outputArtifactId":"Test Execution Report","exitCriteria":["Test evidence attached","Defects triaged or resolved","Release candidate recommended for governance review"],"templatePath":"/out/steps/qa-step-template.md","allowedToolIds":["workspace_list","workspace_read","workspace_search","git_status","run_test","run_docs"],"executionNotes":"QA should execute configured validation commands, summarize the outcome, and capture evidence for downstream governance.","artifactContract":{"requiredInputs":["Build Candidate Manifest","Acceptance Criteria Matrix","QA Intake Packet","Implementation Notes"],"expectedOutputs":["Test Execution Report","Defect and Risk Log","Release Recommendation","QA Sign-off Notes"],"notes":"QA should produce evidence that explains both the verification outcome and remaining risk posture."}},{"id":"STEP-CAPABILITYIDTOKEN-6","name":"Governance Gate","type":"GOVERNANCE_GATE","phase":"GOVERNANCE","layout":{"x":1640,"y":752},"agentId":"AGENT-CAPABILITYIDTOKEN-VALIDATION","action":"Run governance validation and check release controls.","description":"Validate evidence, policy fit, and hand-off completeness before moving into human approval.","inputArtifactId":"Validation Evidence Pack","outputArtifactId":"Governance Assessment","governanceGate":"Release Governance Gate","approverRoles":["Development Manager","Team Lead"],"exitCriteria":["Validation report completed","Required evidence attached","Governance gate cleared for approval"],"templatePath":"/out/steps/governance-gate-template.md","allowedToolIds":["workspace_read","workspace_search","run_docs"],"executionNotes":"Governance validation should review evidence and produce approval-ready documentation, but it should not perform deployments.","artifactContract":{"requiredInputs":["Validation Evidence Pack","Governance Review Summary","Defect and Risk Log","Release Recommendation"],"expectedOutputs":["Governance Assessment","Risk and Control Record","Policy Exception Log","Approval Brief"],"notes":"Governance must distill all release evidence into an approval-ready control package."}},{"id":"STEP-CAPABILITYIDTOKEN-7","name":"Human Approval","type":"HUMAN_APPROVAL","phase":"RELEASE","layout":{"x":1900,"y":928},"agentId":"OWNERAGENTTOKEN","action":"Obtain human approval for release promotion.","description":"Collect final human sign-off and confirm the release decision before handing to DevOps.","inputArtifactId":"Human Approval Packet","outputArtifactId":"Approval Decision Record","approverRoles":["Development Manager","Squad Leader","Team Lead"],"exitCriteria":["Human approval captured","Release decision documented","Deployment cleared to proceed"],"templatePath":"/out/steps/human-approval-template.md","allowedToolIds":[],"executionNotes":"This step always pauses for explicit human approval. The backend runner must not auto-complete it.","artifactContract":{"requiredInputs":["Human Approval Packet","Release Readiness Record","Rollback Plan","Release Window Details"],"expectedOutputs":["Approval Decision Record","Release Authorization","Approver Comments Log"],"notes":"Human approval should capture a durable authorization record and any release conditions or comments."}},{"id":"STEP-CAPABILITYIDTOKEN-8","name":"Release Execution","type":"RELEASE","phase":"RELEASE","layout":{"x":2160,"y":928},"agentId":"AGENT-CAPABILITYIDTOKEN-DEVOPS","action":"Deploy, verify, and close the release.","description":"Execute deployment, verify the release, and publish the final operational status.","inputArtifactId":"Deployment Authorization Packet","outputArtifactId":"Deployment Summary","exitCriteria":["Deployment completed","Operational verification passed","Release summary published"],"templatePath":"/out/steps/release-step-template.md","allowedToolIds":["workspace_read","git_status","run_deploy","run_docs"],"executionNotes":"Release execution can only use capability-configured deployment/doc commands and must remain approval-gated before deployment starts.","artifactContract":{"requiredInputs":["Deployment Authorization Packet","Release Authorization","Deployment Plan","Rollback Plan"],"expectedOutputs":["Deployment Summary","Production Verification Report","Release Notes","Hypercare Handoff"],"notes":"Release execution should leave behind a complete operational record of what was deployed and how it verified."}},{"id":"NODE-CAPABILITYIDTOKEN-END","name":"End","type":"END","phase":"RELEASE","layout":{"x":2420,"y":928},"description":"Terminal completion node for the workflow."}],"edges":[{"id":"EDGE-5MYF9FQH","fromNodeId":"NODE-CAPABILITYIDTOKEN-START","toNodeId":"STEP-CAPABILITYIDTOKEN-1","label":"Begin SDLC delivery","conditionType":"DEFAULT"},{"id":"EDGE-LJSV2YLC","fromNodeId":"STEP-CAPABILITYIDTOKEN-1","toNodeId":"STEP-CAPABILITYIDTOKEN-2","label":"Planning hand-off to business analysis","conditionType":"DEFAULT","handoffProtocolId":"HANDOFF-CAPABILITYIDTOKEN-PLANNING","artifactContract":{"requiredInputs":["Planning Report","Delivery Milestone Plan","Planning Assumptions Log"],"expectedOutputs":["Analysis Intake Packet","Stakeholder Priorities Register"],"notes":"Package the planning baseline so business analysis starts with agreed priorities, milestones, and assumptions."}},{"id":"EDGE-15HKZM9L","fromNodeId":"STEP-CAPABILITYIDTOKEN-2","toNodeId":"STEP-CAPABILITYIDTOKEN-3","label":"Requirements hand-off to architecture","conditionType":"DEFAULT","handoffProtocolId":"HANDOFF-CAPABILITYIDTOKEN-ANALYSIS","artifactContract":{"requiredInputs":["Requirements Specification","Acceptance Criteria Matrix","Assumptions Log","Planning Report"],"expectedOutputs":["Architecture Intake Packet","Open Questions for Design"],"notes":"Package the refined story intent and unresolved assumptions for architecture review."}},{"id":"EDGE-Y6NOD3NB","fromNodeId":"STEP-CAPABILITYIDTOKEN-3","toNodeId":"STEP-CAPABILITYIDTOKEN-4","label":"Design hand-off to development","conditionType":"DEFAULT","handoffProtocolId":"HANDOFF-CAPABILITYIDTOKEN-DESIGN","artifactContract":{"requiredInputs":["Solution Design Document","Architecture Decision Log","Implementation Guardrails"],"expectedOutputs":["Developer Handoff Packet","Build Scope Breakdown"],"notes":"Give development a precise build plan, contract boundaries, and design decisions."}},{"id":"EDGE-5JLBX750","fromNodeId":"STEP-CAPA