    '{"nodes":[{"id":"NODE-CAPABILITYIDTOKEN-START","name":"Start","type":"START","phase":"INCEPTION","layout":{"x":80,"y":48},"description":"Entry point for the Brokerage SDLC Flow."},{"id":"STEP-CAPABILITYIDTOKEN-1","name":"Intent & Scope Definition","type":"DELIVERY","phase":"INCEPTION","layout":{"x":340,"y":48},"agentId":"AGENT-CAPABILITYIDTOKEN-PLANNING","action":"Clarify the intent, scope, and initial viability of the work request.","description":"Frame the objective, define the scope boundary, and capture early proof-of-concept needs before solution shaping begins.","inputArtifactId":"Capability Charter","outputArtifactId":"Inception Brief","exitCriteria":["Intent and scope defined","Business trigger documented","Inception packet ready for elaboration"],"templatePath":"/out/steps/brokerage-inception-template.md","allowedToolIds":[],"executionNotes":"Inception should stay exploratory and documentation-focused without requiring a local repo or modifying delivery assets.","artifactContract":{"requiredInputs":["Capability Charter","Stakeholder Requirements","Business Trigger"],"expectedOutputs":["Inception Brief","Scope Boundary Notes","POC Hypotheses"],"notes":"Inception should leave behind a crisp definition of why the work exists, what it covers, and how much discovery is still needed."}},{"id":"STEP-CAPABILITYIDTOKEN-2","name":"Solution Shaping & Architecture","type":"DELIVERY","phase":"ELABORATION","layout":{"x":600,"y":224},"agentId":"AGENT-CAPABILITYIDTOKEN-ARCHITECT","action":"Shape the solution, architecture, and safe implementation path.","description":"Translate the brokerage request into architecture, design trade-offs, and a construction-ready execution approach.","inputArtifactId":"Brokerage Intake Packet","outputArtifactId":"Solution Shape Document","exitCriteria":["Solution shape documented","Architecture and constraints clarified","Construction plan ready"],"templatePath":"/out/steps/brokerage-elaboration-template.md","allowedToolIds":["workspace