),
workflow_payload AS (
  SELECT
    seed.capability_id,
    seed.capability_slug,
    seed.owner_agent_id,
    template.workflow_suffix,
    template.workflow_name,
    template.workflow_summary,
    REPLACE(
      REPLACE(
        template.workflow_template,
        'OWNERAGENTTOKEN',
        seed.owner_agent_id
      ),
      'CAPABILITYIDTOKEN',
      seed.capability_slug
    )::jsonb AS payload
  FROM tmp_singularity_seed_capabilities seed
  CROSS JOIN workflow_templates template
)
INSERT INTO capability_workflows (
  capability_id,
  id,
  name,
  status,
  workflow_type,
  scope,
  summary,
  schema_version,
  entry_node_id,
  nodes,
  edges,
  steps,
  publish_state,
  created_at,
  updated_at
)
SELECT
  capability_id,
  'WF-' || capability_slug || '-' || workflow_suffix,
  workflow_name,
  'STABLE',
  'SDLC',
  'CAPABILITY',
  workflow_summary,
  2,
  'NODE-' || capability_slug || '-START',
  payload->'nodes',
  payload->'edges',
  payload->'steps',
  'PUBLISHED',
  NOW(),
  NOW()
FROM workflow_payload
ON CONFLICT (capability_id, id) DO UPDATE SET
  name = EXCLUDED.name,
  status = EXCLUDED.status,
  workflow_type = EXCLUDED.workflow_type,
  scope = EXCLUDED.scope,
  summary = EXCLUDED.summary,
  schema_version = EXCLUDED.schema_version,
  entry_node_id = EXCLUDED.entry_node_id,
  nodes = EXCLUDED.nodes,
  edges = EXCLUDED.edges,
  steps = EXCLUDED.steps,
  publish_state = EXCLUDED.publish_state,
  updated_at = NOW();

